mapper.select:
SELECT X.* FROM ( SELECT CN_CD AS id , CN_CD || ' ' || CN_CD_DESC AS text , CN_CD || ' ' || CN_CD_DESC AS title , ROW_NUMBER() OVER(ORDER BY CN_CD_DESC) AS pageindex FROM (SELECT DISTINCT PRODUCT_CD AS CN_CD, PRODUCT_CD AS CN_CD_DESC FROM DOCS_REQUEST_MAPPING WHERE PRODUCT_CD IS NOT NULL) PROD_SRC WHERE 1=1
AND CN_CD_DESC LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

SELECT X.* FROM ( SELECT USER_CD AS id , USER_NM AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE COMPANY_CD != #{companyCd}
AND USER_NM LIKE '%' || #{term} || '%'
AND USE_YN = 'Y' AND DEL_YN = 'N' ) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}
